     1→#!/usr/bin/env node
     2→/**
     3→ * Harness Orchestrator CLI
     4→ *
     5→ * Command-line interface for the harness orchestrator.
     6→ */
     7→
     8→import { Command } from 'commander';
     9→import chalk from 'chalk';
    10→import ora from 'ora';
    11→import { readFileSync } from 'node:fs';
    12→import { resolve } from 'node:path';
    13→
    14→import { DependencyGraph } from '../graph/DependencyGraph.js';
    15→import { CriticalPath } from '../graph/CriticalPath.js';
    16→import { StateManager } from '../state/StateManager.js';
    17→import { AIManager } from '../ai/AIManager.js';
    18→import { Orchestrator } from '../orchestrator/Orchestrator.js';
    19→import { Dashboard } from '../dashboard/Dashboard.js';
    20→import { Verifier } from '../verification/Verifier.js';
    21→import {
    22→  getAllHookTemplates,
    23→  getSettingsTemplate,
    24→} from '../hooks/HookTemplates.js';
    25→import {
    26→  generateVisualTestCommands,
    27→  generateQAChecklist,
    28→  requiresVisualTesting,
    29→  getMcpConfig,
    30→} from '../testing/VisualTesting.js';
    31→import {
    32→  checkFeatureReadyForCommit,
    33→  formatCommitWorkflowCheck,
    34→  generateGitCommitCommand,
    35→  getStagedFiles,
    36→  getUnstagedFiles,
    37→  getUntrackedFiles,
    38→} from '../workflow/CommitWorkflow.js';
    39→import { BasicChecker } from '../doctor/BasicChecker.js';
    40→import type { HarnessConfig, ModelType } from '../types.js';
    41→
    42→const program = new Command();
    43→
    44→program
    45→  .name('harness')
    46→  .alias('h')
    47→  .description('AI Project Manager for harness task orchestration')
    48→  .version('0.1.0');
    49→
    50→// Default features path
    51→const DEFAULT_FEATURES_PATH = 'features.json';
    52→
    53→/**
    54→ * Resolve features path, using default if not provided
    55→ */
    56→function resolveFeaturesPath(path?: string): string {
    57→  return resolve(path || DEFAULT_FEATURES_PATH);
    58→}
    59→
    60→// Analyze command
    61→program
    62→  .command('analyze [features-path]')
    63→  .description('Analyze dependency graph and show execution plan')
    64→  .action((featuresPath?: string) => {
    65→    const resolvedPath = resolveFeaturesPath(featuresPath);
    66→    const content = readFileSync(resolvedPath, 'utf-8');
    67→    const config: HarnessConfig = JSON.parse(content);
    68→
    69→    const graph = new DependencyGraph(config);
    70→    const criticalPath = new CriticalPath(graph);
    71→
    72→    console.log(chalk.bold('\n📊 Dependency Analysis\n'));
    73→
    74→    // Check for cycles
    75→    const cycle = graph.detectCycles();
    76→    if (cycle) {
    77→      console.log(chalk.red('❌ Cycle detected:'), cycle.join(' → '));
    78→      process.exit(1);
    79→    }
    80→    console.log(chalk.green('✓ No cycles detected\n'));
    81→
    82→    // Show features by status
    83→    const pending = graph.getPendingFeatures();
    84→    const completed = graph.getAllFeatures().filter((f) => f.passes);
    85→
    86→    console.log(chalk.bold('Status:'));
    87→    console.log(`  Completed: ${chalk.green(completed.length)}`);
    88→    console.log(`  Pending: ${chalk.yellow(pending.length)}`);
    89→    console.log();
    90→
    91→    // Show ready tasks
    92→    const ready = graph.getReadyTasks();
    93→    console.log(chalk.bold('Ready to run (parallelizable):'));
    94→    if (ready.length === 0) {
    95→      console.log(chalk.dim('  None'));
    96→    } else {
    97→      for (const f of ready) {
    98→        const priority = criticalPath.getPriorityScore(f.id);
    99→        const onCritical = criticalPath.getCriticalPath().includes(f.id);
   100→        const critical = onCritical ? chalk.red(' [CRITICAL]') : '';
   101→        console.log(`  ${chalk.cyan(f.id)}: ${f.description}${critical} (priority: ${priority})`);
   102→      }
   103→    }
   104→    console.log();
   105→
   106→    // Show critical path
   107→    const path = criticalPath.getCriticalPath();
   108→    console.log(chalk.bold('Critical Path:'));
   109→    console.log(`  ${path.map((id) => chalk.red(id)).join(' → ')}`);
   110→    console.log();
   111→
   112→    // Show execution order
   113→    const order = graph.topologicalSort();
   114→    console.log(chalk.bold('Topological Order:'));
   115→    console.log(`  ${order.map((id) => graph.getFeature(id)?.passes ? chalk.green(id) : chalk.yellow(id)).join(' → ')}`);
   116→  });
   117→
   118→// Status command
   119→program
   120→  .command('status [features-path]')
   121→  .description('Show current progress status')
   122→  .action((featuresPath?: string) => {
   123→    const resolvedPath = resolveFeaturesPath(featuresPath);
   124→    const stateManager = new StateManager(resolvedPath);
   125→    const aiManager = new AIManager();
   126→
   127→    const config = stateManager.load();
   128→    const progress = stateManager.getProgress();
   129→
   130→    console.log(chalk.bold('\n📈 Harness Status\n'));
   131→    console.log(`Project: ${chalk.cyan(config.project)}`);
   132→    console.log(`Version: ${config.version}`);
   133→    console.log(`Last Updated: ${config.lastUpdated}`);
   134→    console.log();
   135→
   136→    // Progress bar
   137→    const pct = Math.round((progress.completed / progress.total) * 100);
   138→    const filled = Math.round(pct / 5);
   139→    const bar = '█'.repeat(filled) + '░'.repeat(20 - filled);
   140→    console.log(`Progress: [${bar}] ${pct}%`);
   141→    console.log(`  ${chalk.green(progress.completed)} completed / ${chalk.yellow(progress.pending)} pending`);
   142→    console.log();
   143→
   144→    // Features list
   145→    console.log(chalk.bold('Features:'));
   146→    for (const f of config.features) {
   147→      const status = f.passes ? chalk.green('✓') : chalk.yellow('○');
   148→      const blockedBy = f.blockedBy
   149→        ? chalk.dim(` (blocked by: ${Array.isArray(f.blockedBy) ? f.blockedBy.join(', ') : f.blockedBy})`)
   150→        : '';
   151→      console.log(`  ${status} ${f.id}: ${f.description}${blockedBy}`);
   152→    }
   153→
   154→    // AI summary
   155→    console.log('\n' + aiManager.generateProgressSummary(config.features));
   156→  });
   157→
   158→// Orchestrate command
   159→program
   160→  .command('orchestrate [features-path]')
   161→  .description('Run full orchestration with parallel agents')
   162→  .option('-n, --max-agents <number>', 'Maximum concurrent agents', '3')
   163→  .option('-m, --model <model>', 'Default model (haiku, sonnet, opus)', 'sonnet')
   164→  .option('--dry-run', 'Show plan without executing')
   165→  .option('--timeout <ms>', 'Timeout per task in milliseconds', '600000')
   166→  .option('-d, --dashboard', 'Enable real-time dashboard UI')
   167→  .option('--no-costs', 'Disable cost estimates in dashboard')
   168→  .action(async (featuresPath: string | undefined, options) => {
   169→    const spinner = ora('Loading harness configuration...').start();
   170→
   171→    try {
   172→      const resolvedPath = resolveFeaturesPath(featuresPath);
   173→      const stateManager = new StateManager(resolvedPath);
   174→      const config = stateManager.load();
   175→
   176→      spinner.succeed('Configuration loaded');
   177→
   178→      const pending = config.features.filter((f) => !f.passes).length;
   179→
   180→      if (options.dryRun) {
   181→        console.log(chalk.yellow('\n🔍 Dry Run Mode\n'));
   182→        console.log('Would orchestrate with:');
   183→        console.log(`  Max agents: ${options.maxAgents}`);
   184→        console.log(`  Model: ${options.model}`);
   185→        console.log(`  Features: ${pending} pending`);
   186→        console.log(`  Dashboard: ${options.dashboard ? 'enabled' : 'disabled'}`);
   187→        return;
   188→      }
   189→
   190→      if (pending === 0) {
   191→        console.log(chalk.green('\n✅ All features are already complete!'));
   192→        return;
   193→      }
   194→
   195→      const orchestrator = new Orchestrator(resolvedPath, {
   196→        maxAgents: parseInt(options.maxAgents, 10),
   197→        model: options.model as ModelType,
   198→        timeout: parseInt(options.timeout, 10),
   199→      });
   200→
   201→      if (options.dashboard) {
   202→        // Use real-time dashboard
   203→        const dashboard = new Dashboard(config, {
   204→          liveRefresh: true,
   205→          showCosts: options.costs !== false,
   206→          maxAgents: parseInt(options.maxAgents, 10),
   207→        });
   208→        dashboard.setModel(options.model as 'haiku' | 'sonnet' | 'opus');
   209→        dashboard.attach(orchestrator);
   210→
   211→        const result = await orchestrator.run();
   212→        dashboard.renderFinalSummary();
   213→
   214→        if (result.failed > 0) {
   215→          process.exit(1);
   216→        }
   217→      } else {
   218→        // Classic output mode
   219→        console.log(chalk.bold('\n🚀 Starting Orchestration\n'));
   220→        console.log(`  Max agents: ${chalk.cyan(options.maxAgents)}`);
   221→        console.log(`  Model: ${chalk.cyan(options.model)}`);
   222→        console.log(`  Pending: ${chalk.yellow(pending)} features`);
   223→        console.log();
   224→
   225→        // Event handlers for progress display
   226→        orchestrator.on('taskDispatched', ({ taskId, feature }) => {
   227→          console.log(chalk.blue(`▶ Started ${taskId}: ${feature.description}`));
   228→        });
   229→
   230→        orchestrator.on('taskSucceeded', ({ taskId }) => {
   231→          console.log(chalk.green(`✓ Completed ${taskId}`));
   232→        });
   233→
   234→        orchestrator.on('taskFailed', ({ taskId, error }) => {
   235→          console.log(chalk.red(`✗ Failed ${taskId}: ${error}`));
   236→        });
   237→
   238→        orchestrator.on('deadlock', ({ pending }) => {
   239→          console.log(chalk.red(`\n⚠️  Deadlock detected! ${pending} tasks stuck.`));
   240→        });
   241→
   242→        orchestrator.on('shutdown', ({ signal }) => {
   243→          console.log(chalk.yellow(`\n⚠️  Received ${signal}, shutting down gracefully...`));
   244→        });
   245→
   246→        const runSpinner = ora('Running orchestration...').start();
   247→        const result = await orchestrator.run();
   248→        runSpinner.stop();
   249→
   250→        console.log(chalk.bold('\n📊 Results\n'));
   251→        console.log(`  Completed: ${chalk.green(result.completed)}`);
   252→        console.log(`  Failed: ${chalk.red(result.failed)}`);
   253→
   254→        if (result.failed === 0) {
   255→          console.log(chalk.green('\n✅ Orchestration completed successfully!'));
   256→        } else {
   257→          console.log(chalk.yellow(`\n⚠️  ${result.failed} task(s) failed.`));
   258→          process.exit(1);
   259→        }
   260→      }
   261→    } catch (error) {
   262→      spinner.fail('Orchestration failed');
   263→      console.error(error);
   264→      process.exit(1);
   265→    }
   266→  });
   267→
   268→// Dashboard command (standalone)
   269→program
   270→  .command('dashboard [features-path]')
   271→  .description('Show real-time dashboard (attaches to running orchestration)')
   272→  .option('--no-costs', 'Disable cost estimates')
   273→  .action((featuresPath: string | undefined, options) => {
   274→    const resolvedPath = resolveFeaturesPath(featuresPath);
   275→    const stateManager = new StateManager(resolvedPath);
   276→    const config = stateManager.load();
   277→
   278→    const dashboard = new Dashboard(config, {
   279→      liveRefresh: false,
   280→      showCosts: options.costs !== false,
   281→    });
   282→
   283→    dashboard.render();
   284→  });
   285→
   286→// Verify command
   287→program
   288→  .command('verify [features-path]')
   289→  .description('Verify feature completion and show verification status')
   290→  .option('-f, --feature <id>', 'Verify a specific feature')
   291→  .option('--all', 'Verify all completed features')
   292→  .action(async (featuresPath: string | undefined, options) => {
   293→    const resolvedPath = resolveFeaturesPath(featuresPath);
   294→    const verifier = new Verifier(resolvedPath);
   295→    const stateManager = new StateManager(resolvedPath);
   296→    const config = stateManager.load();
   297→
   298→    console.log(chalk.bold('\n🔍 Feature Verification\n'));
   299→
   300→    // Get git status
   301→    const gitStatus = verifier.getGitStatus();
   302→    if (gitStatus) {
   303→      console.log(chalk.bold('Git Status:'));
   304→      console.log(`  Branch: ${chalk.cyan(gitStatus.branch)}`);
   305→      console.log(`  Clean: ${gitStatus.isClean ? chalk.green('Yes') : chalk.yellow('No')}`);
   306→      if (gitStatus.ahead > 0 || gitStatus.behind > 0) {
   307→        console.log(`  Ahead: ${gitStatus.ahead}, Behind: ${gitStatus.behind}`);
   308→      }
   309→      console.log();
   310→    }
   311→
   312→    // List feature branches
   313→    const branches = verifier.listFeatureBranches();
   314→    if (branches.length > 0) {
   315→      console.log(chalk.bold('Feature Branches:'));
   316→      for (const branch of branches) {
   317→        const status = branch.isMerged ? chalk.green('merged') : chalk.yellow('pending');
   318→        console.log(`  ${branch.name} (${branch.featureId}) - ${status}`);
   319→      }
   320→      console.log();
   321→    }
   322→
   323→    // Verify features
   324→    const featuresToVerify = options.feature
   325→      ? config.features.filter(f => f.id === options.feature)
   326→      : options.all
   327→        ? config.features.filter(f => f.passes)
   328→        : config.features.filter(f => f.passes).slice(0, 5);
   329→
   330→    if (featuresToVerify.length === 0) {
   331→      console.log(chalk.dim('No features to verify'));
   332→      return;
   333→    }
   334→
   335→    console.log(chalk.bold('Verification Results:'));
   336→    for (const feature of featuresToVerify) {
   337→      const result = await verifier.verifyFeature(feature);
   338→      const icon = result.passed ? chalk.green('✓') : chalk.red('✗');
   339→      console.log(`\n${icon} ${chalk.bold(result.featureId)}: ${feature.description}`);
   340→      for (const check of result.checks) {
   341→        const checkIcon = check.passed ? chalk.green('✓') : chalk.red('✗');
   342→        console.log(`    ${checkIcon} ${check.name}: ${chalk.dim(check.details || '')}`);
   343→      }
   344→    }
   345→  });
   346→
   347→// Rollback command
   348→program
   349→  .command('rollback [features-path]')
   350→  .description('Rollback a feature to its previous state')
   351→  .requiredOption('-f, --feature <id>', 'Feature ID to rollback')
   352→  .option('--delete-remote', 'Also delete remote branch')
   353→  .action(async (featuresPath: string | undefined, options) => {
   354→    const resolvedPath = resolveFeaturesPath(featuresPath);
   355→    const verifier = new Verifier(resolvedPath);
   356→    const stateManager = new StateManager(resolvedPath);
   357→
   358→    const featureId = options.feature.toUpperCase();
   359→
   360→    console.log(chalk.bold(`\n🔄 Rolling back feature ${featureId}\n`));
   361→
   362→    const gitStatus = verifier.getGitStatus();
   363→    if (!gitStatus) {
   364→      console.log(chalk.red('Not a git repository. Cannot rollback.'));
   365→      process.exit(1);
   366→    }
   367→
   368→    const branches = verifier.listFeatureBranches();
   369→    const branch = branches.find(b => b.featureId === featureId);
   370→
   371→    if (!branch) {
   372→      console.log(chalk.yellow(`No branch found for feature ${featureId}`));
   373→      console.log('Available feature branches:');
   374→      for (const b of branches) {
   375→        console.log(`  - ${b.name} (${b.featureId})`);
   376→      }
   377→      return;
   378→    }
   379→
   380→    console.log(`Branch: ${chalk.cyan(branch.name)}`);
   381→    console.log(`Merged: ${branch.isMerged ? chalk.green('Yes') : chalk.yellow('No')}`);
   382→    console.log();
   383→
   384→    // Update state to mark as not complete
   385→    const config = stateManager.load();
   386→    const feature = config.features.find(f => f.id === featureId);
   387→    if (feature) {
   388→      feature.passes = false;
   389→      await stateManager.save(config);
   390→      console.log(chalk.green(`✓ Marked ${featureId} as incomplete in features.json`));
   391→    }
   392→
   393→    // Note: In a real implementation, we'd use the GitManager to delete the branch
   394→    console.log(chalk.dim(`To delete the branch manually: git branch -D ${branch.name}`));
   395→
   396→    console.log(chalk.green('\n✓ Rollback complete'));
   397→  });
   398→
   399→// Branches command
   400→program
   401→  .command('branches [features-path]')
   402→  .description('List and manage feature branches')
   403→  .option('--cleanup', 'Delete merged feature branches')
   404→  .action((featuresPath: string | undefined, options) => {
   405→    const resolvedPath = resolveFeaturesPath(featuresPath);
   406→    const verifier = new Verifier(resolvedPath);
   407→
   408→    const gitStatus = verifier.getGitStatus();
   409→    if (!gitStatus) {
   410→      console.log(chalk.red('Not a git repository.'));
   411→      process.exit(1);
   412→    }
   413→
   414→    console.log(chalk.bold('\n🌿 Feature Branches\n'));
   415→    console.log(`Current branch: ${chalk.cyan(gitStatus.branch)}`);
   416→    console.log();
   417→
   418→    const branches = verifier.listFeatureBranches();
   419→
   420→    if (branches.length === 0) {
   421→      console.log(chalk.dim('No feature branches found'));
   422→      return;
   423→    }
   424→
   425→    const merged = branches.filter(b => b.isMerged);
   426→    const pending = branches.filter(b => !b.isMerged);
   427→
   428→    if (pending.length > 0) {
   429→      console.log(chalk.bold('Pending (not merged):'));
   430→      for (const branch of pending) {
   431→        console.log(`  ${chalk.yellow('○')} ${branch.name} (${branch.featureId})`);
   432→      }
   433→      console.log();
   434→    }
   435→
   436→    if (merged.length > 0) {
   437→      console.log(chalk.bold('Merged:'));
   438→      for (const branch of merged) {
   439→        console.log(`  ${chalk.green('✓')} ${branch.name} (${branch.featureId})`);
   440→      }
   441→      console.log();
   442→    }
   443→
   444→    if (options.cleanup && merged.length > 0) {
   445→      console.log(chalk.bold('Cleaning up merged branches...'));
   446→      const deleted = verifier.cleanupMergedBranches();
   447→      console.log(chalk.green(`✓ Deleted ${deleted.length} branch(es)`));
   448→    } else if (merged.length > 0) {
   449→      console.log(chalk.dim(`Run with --cleanup to delete ${merged.length} merged branch(es)`));
   450→    }
   451→  });
   452→
   453→// Init command - bootstrap a new harness project
   454→program
   455→  .command('init [project-path]')
   456→  .description('Initialize a new harness project with standard structure')
   457→  .option('-n, --name <name>', 'Project name')
   458→  .option('--no-hooks', 'Skip generating hooks')
   459→  .option('--no-git', 'Skip git initialization')
   460→  .action(async (projectPath: string | undefined, options) => {
   461→    const targetDir = resolve(projectPath || '.');
   462→    const projectName = options.name || targetDir.split('/').pop() || 'my-project';
   463→
   464→    console.log(chalk.bold(`\n🚀 Initializing Harness Project: ${projectName}\n`));
   465→
   466→    const { existsSync, mkdirSync, writeFileSync } = await import('node:fs');
   467→
   468→    // Create directory if needed
   469→    if (!existsSync(targetDir)) {
   470→      mkdirSync(targetDir, { recursive: true });
   471→      console.log(chalk.green(`✓ Created directory: ${targetDir}`));
   472→    }
   473→
   474→    // 1. Generate features.json
   475→    const featuresPath = resolve(targetDir, 'features.json');
   476→    if (!existsSync(featuresPath)) {
   477→      const featuresTemplate = {
   478→        project: projectName,
   479→        version: '0.1.0',
   480→        description: `Harness configuration for ${projectName}`,
   481→        lastUpdated: new Date().toISOString().split('T')[0],
   482→        features: [
   483→          {
   484→            id: 'F001',
   485→            category: 'setup',
   486→            description: 'Project initialization and environment setup',
   487→            steps: [
   488→              'Verify development environment',
   489→              'Install dependencies',
   490→              'Configure build tools',
   491→              'Run initial build'
   492→            ],
   493→            passes: false,
   494→            blockedBy: null,
   495→            notes: 'First feature - no dependencies'
   496→          }
   497→        ]
   498→      };
   499→      writeFileSync(featuresPath, JSON.stringify(featuresTemplate, null, 2));
   500→      console.log(chalk.green('✓ Created features.json'));
   501→    } else {
   502→      console.log(chalk.yellow('○ features.json already exists, skipping'));
   503→    }
   504→
   505→    // 2. Generate claude-progress.txt
   506→    const progressPath = resolve(targetDir, 'claude-progress.txt');
   507→    if (!existsSync(progressPath)) {
   508→      const today = new Date().toISOString().split('T')[0];
   509→      const progressTemplate = `# ${projectName} - Progress Log
   510→
   511→## Project Goal
   512→[Describe the main objective of this project]
   513→
   514→---
   515→
   516→## Session 1 - ${today} - Project Initialization
   517→
   518→### Context
   519→Initial harness setup.
   520→
   521→### Completed ✅
   522→- Created harness structure with \`harness init\`
   523→- Generated features.json with initial feature
   524→
   525→### Current State
   526→| Feature | Status | Notes |
   527→|---------|--------|-------|
   528→| F001 | ○ Pending | Project setup |
   529→
   530→### Next Session Priorities
